import React, { useState, useEffect } from 'react';
import VideoCompressor from './VideoCompressor';
import { db } from './firebase'; 
import { collection, addDoc, query, onSnapshot, serverTimestamp, doc, deleteDoc, orderBy } from 'firebase/firestore';

function App() {
  const [uploading, setUploading] = useState(false);
    const [showSettings, setShowSettings] = useState(false);
      const [gallery, setGallery] = useState([]);
        const [token, setToken] = useState(localStorage.getItem('tg_token') || '');
          const [chatId, setChatId] = useState(localStorage.getItem('tg_chatid') || '');

            useEffect(() => {
                if (!db) return;
                    const q = query(collection(db, "media"), orderBy("timestamp", "desc"));
                        const unsubscribe = onSnapshot(q, (snapshot) => {
                              const items = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
                                    setGallery(items);
                                        });
                                            return () => unsubscribe();
                                              }, []);

                                                const handleUpload = async (fileUrl, fileName, fileSize) => {
                                                    if (!token || !chatId) return alert('Configura el Bot en ⚙️');
                                                        setUploading(true);
                                                            try {
                                                                  const response = await fetch(fileUrl);
                                                                        const blob = await response.blob();
                                                                              const formData = new FormData();
                                                                                    formData.append('chat_id', chatId);
                                                                                          const isVideo = blob.type.includes('video');
                                                                                                const endpoint = isVideo ? 'sendVideo' : 'sendPhoto';
                                                                                                      formData.append(isVideo ? 'video' : 'photo', blob, fileName);

                                                                                                            const tgRes = await fetch(`https://api.telegram.org/bot${token}/${endpoint}`, {
                                                                                                                    method: 'POST',
                                                                                                                            body: formData
                                                                                                                                  });
                                                                                                                                        const tgData = await tgRes.json();

                                                                                                                                              if (tgRes.ok) {
                                                                                                                                                      await addDoc(collection(db, "media"), {
                                                                                                                                                                fileName,
                                                                                                                                                                          type: blob.type,
                                                                                                                                                                                    messageId: tgData.result.message_id, 
                                                                                                                                                                                              timestamp: serverTimestamp(),
                                                                                                                                                                                                        preview: fileUrl 
                                                                                                                                                                                                                });
                                                                                                                                                                                                                      }
                                                                                                                                                                                                                          } catch (e) {
                                                                                                                                                                                                                                alert('Error: ' + e.message);
                                                                                                                                                                                                                                    } finally {
                                                                                                                                                                                                                                          setUploading(false);
                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                };

                                                                                                                                                                                                                                                  const deleteItem = async (id, messageId) => {
                                                                                                                                                                                                                                                      if(window.confirm("¿Eliminar archivo?")) {
                                                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                                                    await fetch(`https://api.telegram.org/bot${token}/deleteMessage?chat_id=${chatId}&message_id=${messageId}`);
                                                                                                                                                                                                                                                                            await deleteDoc(doc(db, "media", id));
                                                                                                                                                                                                                                                                                  } catch (err) { console.log(err); }
                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                        };

                                                                                                                                                                                                                                                                                          return (
                                                                                                                                                                                                                                                                                              <div className="min-h-screen bg-black text-white p-4">
                                                                                                                                                                                                                                                                                                    {/* ESTILO FORZADO PARA MINIATURAS */}
                                                                                                                                                                                                                                                                                                          <style>{`
                                                                                                                                                                                                                                                                                                                  .grid-gallery {
                                                                                                                                                                                                                                                                                                                            display: grid;
                                                                                                                                                                                                                                                                                                                                      grid-template-columns: repeat(3, 1fr);
                                                                                                                                                                                                                                                                                                                                                gap: 8px;
                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                .thumb-container {
                                                                                                                                                                                                                                                                                                                                                                          position: relative;
                                                                                                                                                                                                                                                                                                                                                                                    width: 100%;
                                                                                                                                                                                                                                                                                                                                                                                              padding-top: 100%; /* Hace que sea un cuadrado perfecto */
                                                                                                                                                                                                                                                                                                                                                                                                        background: #111;
                                                                                                                                                                                                                                                                                                                                                                                                                  border-radius: 12px;
                                                                                                                                                                                                                                                                                                                                                                                                                            overflow: hidden;
                                                                                                                                                                                                                                                                                                                                                                                                                                      border: 1px solid #222;
                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                      .thumb-content {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                position: absolute;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          top: 0; left: 0; width: 100%; height: 100%;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    object-fit: cover;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .play-icon {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              position: absolute;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        top: 50%; left: 50%;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  transform: translate(-50%, -50%);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            background: rgba(0,0,0,0.5);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      width: 30px; height: 30px;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                border-radius: 50%;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          display: flex; align-items: center; justify-content: center;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    border: 1px solid rgba(255,255,255,0.3);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  `}</style>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <header className="flex justify-between items-center mb-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <h1 className="text-xl font-bold text-blue-500 italic">CloudGallery</h1>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <button onClick={() => setShowSettings(!showSettings)} className="text-xl">⚙️</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </header>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {showSettings ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="bg-gray-900 p-6 rounded-2xl">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <input type="password" value={token} onChange={e => setToken(e.target.value)} className="w-full bg-black p-3 rounded mb-4" placeholder="Token" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <input value={chatId} onChange={e => setChatId(e.target.value)} className="w-full bg-black p-3 rounded mb-4" placeholder="Chat ID" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <button onClick={() => setShowSettings(false)} className="w-full bg-blue-600 p-3 rounded font-bold">CERRAR</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <main>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="bg-gray-900 p-4 rounded-3xl mb-8 border border-gray-800">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <VideoCompressor onVideoReady={handleUpload} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {uploading && <p className="text-center text-blue-400 text-xs animate-pulse mt-2">SUBIENDO...</p>}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="grid-gallery">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {gallery.map(item => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div key={item.id} className="thumb-container">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {item.preview ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  item.type?.includes('video') ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <video src={item.preview} className="thumb-content opacity-60" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="play-icon">▶</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <img src={item.preview} className="thumb-content" alt="" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="thumb-content flex items-center justify-center text-xs">DOC</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  onClick={() => deleteItem(item.id, item.messageId)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    className="absolute top-1 right-1 bg-red-600 w-5 h-5 rounded-full text-[10px] z-10"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >✕</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </main>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            export default App;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            